<span class="line"><span style="--shiki-light:#4078F2;--shiki-dark:#61AFEF;">sudo</span><span style="--shiki-light:#50A14F;--shiki-dark:#98C379;"> certbot</span><span style="--shiki-light:#50A14F;--shiki-dark:#98C379;"> renew</span><span style="--shiki-light:#986801;--shiki-dark:#D19A66;"> --dry-run</span></span>
